defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)
    {:ok, assign(socket, post: post)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto p-6">
      <article class="bg-white shadow-lg rounded-lg p-8">
        <header class="mb-6">
          <h1 class="text-4xl font-bold mb-2"><%= @post.title %></h1>
          <div class="text-gray-600 text-sm">
            <span>By <%= @post.author %></span>
            <span class="mx-2">•</span>
            <span><%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %></span>
          </div>
        </header>
        
        <div class="prose max-w-none">
          <%= raw @post.content %>
        </div>
        
        <footer class="mt-8 pt-6 border-t">
          <div class="flex gap-4">
            <.link navigate={~p"/posts"} class="text-blue-600 hover:underline">
              ← Back to Posts
            </.link>
          </div>
        </footer>
      </article>
      
      <section class="mt-8">
        <h2 class="text-2xl font-bold mb-4">Comments</h2>
        <%= if @post.comments do %>
          <%= for comment <- @post.comments do %>
            <div class="bg-gray-50 p-4 rounded mb-4">
              <div class="font-semibold mb-2"><%= comment.author %></div>
              <div class="text-gray-700">
                <%= raw comment.body %>
              </div>
            </div>
          <% end %>
        <% end %>
      </section>
    </div>
    """
  end
end

defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, posts: posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-6xl mx-auto p-6">
      <h1 class="text-4xl font-bold mb-8">Blog Posts</h1>
      
      <div class="grid gap-6">
        <%= for post <- @posts do %>
          <article class="bg-white shadow rounded-lg p-6 hover:shadow-lg transition">
            <h2 class="text-2xl font-bold mb-2">
              <.link navigate={~p"/posts/#{post.id}"} class="text-blue-600 hover:underline">
                <%= post.title %>
              </.link>
            </h2>
            
            <div class="text-gray-600 text-sm mb-4">
              <span>By <%= post.author %></span>
              <span class="mx-2">•</span>
              <span><%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %></span>
            </div>
            
            <div class="prose max-w-none line-clamp-3">
              <%= raw post.excerpt || String.slice(post.content, 0..200) %>
            </div>
            
            <div class="mt-4">
              <.link navigate={~p"/posts/#{post.id}"} class="text-blue-600 hover:underline">
                Read more →
              </.link>
            </div>
          </article>
        <% end %>
      </div>
    </div>
    """
  end
end

defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})
    {:ok, assign(socket, form: to_form(changeset), preview_content: nil)}
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, form: to_form(changeset))}
  end

  @impl true
  def handle_event("preview", %{"post" => post_params}, socket) do
    {:noreply, assign(socket, preview_content: post_params["content"])}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case Posts.create_post(post_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post created successfully")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, %Ecto.Changeset{} = changeset} ->
        {:noreply, assign(socket, form: to_form(changeset))}
    end
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto p-6">
      <h1 class="text-3xl font-bold mb-6">Create New Post</h1>
      
      <.form for={@form} phx-change="validate" phx-submit="save" class="space-y-6">
        <div>
          <.input field={@form[:title]} type="text" label="Title" />
        </div>
        
        <div>
          <.input field={@form[:author]} type="text" label="Author" />
        </div>
        
        <div>
          <.input field={@form[:content]} type="textarea" label="Content (HTML allowed)" rows="15" />
        </div>
        
        <div class="flex gap-4">
          <button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700">
            Publish Post
          </button>
          
          <button type="button" phx-click="preview" class="bg-gray-600 text-white px-6 py-2 rounded hover:bg-gray-700">
            Preview
          </button>
        </div>
      </.form>
      
      <%= if @preview_content do %>
        <div class="mt-8 border-t pt-8">
          <h2 class="text-2xl font-bold mb-4">Preview</h2>
          <div class="bg-white shadow rounded-lg p-6">
            <div class="prose max-w-none">
              <%= raw @preview_content %>
            </div>
          </div>
        </div>
      <% end %>
    </div>
    """
  end
end